class Solution:
    def maximumSumOfHeights(self, maxHeights: List[int]) -> int:
        n = len(maxHeights)
        max_sum = 0

        for peak in range(n):
            # Build the heights array with peak at 'peak'
            heights = [0] * n
            # Left side: non-decreasing up to peak
            heights[peak] = maxHeights[peak]
            for i in range(peak - 1, -1, -1):
                heights[i] = min(maxHeights[i], heights[i + 1])
            # Right side: non-increasing from peak
            for i in range(peak + 1, n):
                heights[i] = min(maxHeights[i], heights[i - 1])
            # Compute the sum
            current_sum = sum(heights)
            if current_sum > max_sum:
                max_sum = current_sum

        return max_sum
